/**
 * SAML Relying Party CREATE handler (samlgw2)
 *
 * Creates a new SAML RP on samlgw2, adds the OIDC callback URL
 * to the Cognito SAML client, and stores SP info in DynamoDB.
 */

import { PutItemCommand } from '@aws-sdk/client-dynamodb';
import {
  CognitoIdentityProviderClient,
  DescribeUserPoolClientCommand,
  UpdateUserPoolClientCommand,
} from '@aws-sdk/client-cognito-identity-provider';
import {
  createSamlGw2ClientFromEnv,
  buildSamlgw2ItorgId,
} from '../samlgw2-client/index.mjs';
import { getTemplate } from '../samlgw2-client/rp-templates.mjs';

const cognito = new CognitoIdentityProviderClient({ region: process.env.AWS_REGION });

/**
 * Look up the samlgw2 IT Org ID for a tenant.
 * Queries the org record from DynamoDB, falls back to computing it.
 */
async function getSamlgw2ItorgId(tenantOrgId, dynamodb, tenantTable) {
  try {
    const { QueryCommand } = await import('@aws-sdk/client-dynamodb');
    const result = await dynamodb.send(new QueryCommand({
      TableName: tenantTable,
      KeyConditionExpression: 'id = :id AND begins_with(sk, :sk_prefix)',
      ExpressionAttributeValues: {
        ':id': { S: `ORG#${tenantOrgId}` },
        ':sk_prefix': { S: 'ORG#' },
      },
      ProjectionExpression: 'samlgw2_itorg_id',
    }));

    const stored = result.Items?.[0]?.samlgw2_itorg_id?.S;
    if (stored) return stored;
  } catch (e) {
    console.log('Failed to query org samlgw2_itorg_id, computing fallback:', e.message);
  }

  return buildSamlgw2ItorgId(process.env.ACCOUNT_ID, tenantOrgId);
}

/**
 * Look up tenant info (orgId, userPoolId, samlClientId) from the tenant table.
 */
async function getTenantInfo(tenantId, dynamodb, tenantTable) {
  const { QueryCommand } = await import('@aws-sdk/client-dynamodb');
  const result = await dynamodb.send(new QueryCommand({
    TableName: tenantTable,
    KeyConditionExpression: 'id = :id AND begins_with(sk, :sk_prefix)',
    ExpressionAttributeValues: {
      ':id': { S: `TENANT#${tenantId}` },
      ':sk_prefix': { S: 'TENANT#' },
    },
  }));

  if (!result.Items || result.Items.length === 0) {
    throw new Error(`Tenant '${tenantId}' not found`);
  }

  const item = result.Items[0];
  return {
    orgId: item.org_id?.S,
    userPoolId: item.userpool?.S,
    samlClientId: item.samlClientId?.S,
    oauthDomain: item.oauthDomain?.S,
  };
}

/**
 * Add a callback URL to the Cognito SAML client.
 */
async function addCallbackUrlToSamlClient(userPoolId, samlClientId, newCallbackUrl) {
  // Get current client config
  const describeResult = await cognito.send(new DescribeUserPoolClientCommand({
    UserPoolId: userPoolId,
    ClientId: samlClientId,
  }));

  const client = describeResult.UserPoolClient;
  const currentCallbackUrls = client.CallbackURLs || [];

  // Check if URL already exists
  if (currentCallbackUrls.includes(newCallbackUrl)) {
    console.log('Callback URL already exists, skipping');
    return;
  }

  // Add new callback URL
  const updatedCallbackUrls = [...currentCallbackUrls, newCallbackUrl];

  await cognito.send(new UpdateUserPoolClientCommand({
    UserPoolId: userPoolId,
    ClientId: samlClientId,
    ClientName: client.ClientName,
    RefreshTokenValidity: client.RefreshTokenValidity,
    AccessTokenValidity: client.AccessTokenValidity,
    IdTokenValidity: client.IdTokenValidity,
    TokenValidityUnits: client.TokenValidityUnits,
    ExplicitAuthFlows: client.ExplicitAuthFlows,
    SupportedIdentityProviders: client.SupportedIdentityProviders,
    AllowedOAuthFlows: client.AllowedOAuthFlows,
    AllowedOAuthScopes: client.AllowedOAuthScopes,
    AllowedOAuthFlowsUserPoolClient: client.AllowedOAuthFlowsUserPoolClient,
    CallbackURLs: updatedCallbackUrls,
    LogoutURLs: client.LogoutURLs,
    PreventUserExistenceErrors: client.PreventUserExistenceErrors,
  }));

  console.log(`Added callback URL to SAML client: ${newCallbackUrl}`);
}

/**
 * Store RP info in DynamoDB spinfo table.
 */
async function storeSPInfo(payload, dynamodb, spInfoTable) {
  const params = {
    Item: {
      id: { S: `#SAML#${payload.rpName}` },
      name: { S: payload.name || payload.display_name || '' },
      logoUrl: { S: payload.logoUrl || payload.logo_url || '' },
      serviceUrl: { S: payload.serviceUrl || payload.login_url || '' },
      released: { BOOL: payload.released ? true : false },
      template: { S: payload.template || 'custom' },
      rpName: { S: payload.rpName },
      idpMetadataUrl: { S: payload.idpMetadataUrl || '' },
      callbackUrl: { S: payload.callbackUrl || '' },
      metadataUrl: { S: payload.metadataUrl || '' },
    },
    ReturnConsumedCapacity: 'TOTAL',
    TableName: spInfoTable,
  };

  await dynamodb.send(new PutItemCommand(params));
  return payload;
}

/**
 * Main POST handler: Create a new SAML Relying Party.
 */
export const postResData = async (payload, dynamodb, tenantId, tenantTable, spInfoTable) => {
  console.log('postResData Input:', payload);

  const { rpName, template: templateId } = payload;

  if (!rpName) {
    return {
      statusCode: 400,
      body: JSON.stringify({ data: 'rpName is required', error: 'rpName is required' }),
    };
  }

  // Get tenant info
  const tenantInfo = await getTenantInfo(tenantId, dynamodb, tenantTable);
  if (!tenantInfo.orgId) {
    return {
      statusCode: 400,
      body: JSON.stringify({ data: 'Tenant has no associated organization', error: 'No org found' }),
    };
  }

  // Get samlgw2 IT Org ID
  const itorgId = await getSamlgw2ItorgId(tenantInfo.orgId, dynamodb, tenantTable);
  const customerName = tenantId.toLowerCase();

  // Build RP config from template + overrides
  let rpConfig;
  if (templateId && templateId !== 'custom') {
    const tmpl = getTemplate(templateId);
    if (!tmpl) {
      return {
        statusCode: 400,
        body: JSON.stringify({ data: `Unknown template: ${templateId}`, error: 'Invalid template' }),
      };
    }
    // Merge template with any user overrides
    rpConfig = {
      display_name: payload.display_name || tmpl.display_name,
      login_url: payload.login_url || tmpl.login_url,
      logo_url: payload.logo_url || tmpl.logo_url,
      sp: {
        metadata_url: payload.sp_metadata_url || tmpl.sp.metadata_url,
      },
      claim_mappings: payload.claim_mappings || tmpl.claim_mappings,
      saml: payload.saml || tmpl.saml,
    };
  } else {
    // Custom: user provides everything
    rpConfig = {
      display_name: payload.display_name || payload.name || '',
      login_url: payload.login_url || payload.serviceUrl || '',
      logo_url: payload.logo_url || payload.logoUrl || '',
      sp: {
        metadata_url: payload.sp_metadata_url || payload.metadataUrl || '',
      },
      claim_mappings: payload.claim_mappings || {
        saml_to_oidc: {},
        oidc_to_saml: {},
      },
      saml: payload.saml || {
        nameid: {
          format: 'urn:oasis:names:tc:SAML:2.0:nameid-format:persistent',
          source_claim: 'email',
        },
      },
    };
  }

  if (!rpConfig.sp.metadata_url) {
    return {
      statusCode: 400,
      body: JSON.stringify({ data: 'SP metadata URL is required', error: 'Missing sp_metadata_url' }),
    };
  }

  // 1. Create RP on samlgw2
  const samlgw2 = createSamlGw2ClientFromEnv();
  try {
    await samlgw2.createRelyingParty(itorgId, customerName, rpName.toLowerCase(), rpConfig);
    console.log(`RP '${rpName}' created on samlgw2`);
  } catch (gw2Error) {
    console.error('samlgw2 create RP error:', gw2Error);
    return {
      statusCode: gw2Error.status || 500,
      body: JSON.stringify({
        data: `Failed to create RP on SAML Gateway: ${gw2Error.message}`,
        error: gw2Error.message,
      }),
    };
  }

  // 2. Build URLs
  const idpMetadataUrl = samlgw2.getIdpMetadataUrl(itorgId, customerName, rpName.toLowerCase());
  const callbackUrl = samlgw2.getOidcCallbackUrl(itorgId, customerName, rpName.toLowerCase());

  // 3. Add callback URL to Cognito SAML client
  try {
    await addCallbackUrlToSamlClient(
      tenantInfo.userPoolId,
      tenantInfo.samlClientId,
      callbackUrl,
    );
    console.log('Callback URL added to Cognito SAML client');
  } catch (cognitoError) {
    console.error('Failed to add callback URL to Cognito (non-fatal):', cognitoError.message);
    // Non-fatal: RP was created on samlgw2, callback can be added manually
  }

  // 4. Store SP info in DynamoDB
  const spData = {
    rpName: rpName.toLowerCase(),
    name: rpConfig.display_name,
    logoUrl: rpConfig.logo_url,
    serviceUrl: rpConfig.login_url,
    released: payload.released || false,
    template: templateId || 'custom',
    idpMetadataUrl,
    callbackUrl,
    metadataUrl: rpConfig.sp.metadata_url,
  };

  await storeSPInfo(spData, dynamodb, spInfoTable);

  const data = {
    id: rpName.toLowerCase(),
    rpName: rpName.toLowerCase(),
    name: rpConfig.display_name,
    logoUrl: rpConfig.logo_url,
    serviceUrl: rpConfig.login_url,
    released: payload.released || false,
    template: templateId || 'custom',
    metadataUrl: rpConfig.sp.metadata_url,
    idpMetadataUrl,
    callbackUrl,
  };

  return {
    statusCode: 200,
    body: JSON.stringify({ data }),
  };
};

export default postResData;
